#include<bits/stdc++.h>
using namespace std;
int fa[100010],ans;
bool prime[100010];
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
void merge(int x,int y)
{
    int a=find(x),b=find(y);
    if(a!=b)
    {
        fa[a]=b;
        ans--;
    }
}
int main()
{
    int a,b,p;
    scanf("%d%d%d",&a,&b,&p);
    ans=b-a+1;
    for(int i=a;i<=b;i++)
    {
        fa[i]=i;
    }
    for(int i=2;i<=b;i++)
    {
        if(prime[i])
        {
            continue;
        }
        for(int j=i*2;j<=b;j+=i)
        {
            prime[j]=1;
            if(i>=p&&j-i>=a)
            {
                merge(j,j-i);
            }
        }
    }
    printf("%d",ans);
    return 0;
}
